radix2_notw_kernel_fwd_avx2(
    const double * __restrict__ in_re, const double * __restrict__ in_im,
    double * __restrict__ out_re, double * __restrict__ out_im,
    size_t K)
{
    for (size_t k = 0; k < K; k += 4) {
        __m256d ar = LD(&in_re[k]), ai = LD(&in_im[k]);
        __m256d br = LD(&in_re[K+k]), bi = LD(&in_im[K+k]);
        ST(&out_re[k],_mm256_add_pd(ar,br));
        ST(&out_im[k],_mm256_add_pd(ai,bi));
        ST(&out_re[K+k],_mm256_sub_pd(ar,br));
        ST(&out_im[K+k],_mm256_sub_pd(ai,bi));
    }
}

