        const __m256d x0r = LD(&rio_re[m + 0*ios]), x0i = LD(&rio_im[m + 0*ios]);
        const __m256d r1r = LD(&rio_re[m + 1*ios]), r1i = LD(&rio_im[m + 1*ios]);
        const __m256d wr = LD(&W_re[0*me+m]), wi = LD(&W_im[0*me+m]);
